// Replicate the exact functions from route.ts
function getMonday\(date\) {
  const d = new Date\(date\);
  const day = d.getDay\(\);
  const diff = d.getDate\(\) - day + \(day === 0 ? -6 : 1\);
  d.setDate\(diff\);
  return d;
}

function calculateTaskDueDate\(launchDate, weekNumber\) {
  const launch = new Date\(launchDate + 'T12:00:00'\);
  const rawDate = new Date\(launch.getTime\(\) + weekNumber * 7 * 24 * 60 * 60 * 1000\);
  const monday = getMonday\(rawDate\);
  return monday.toISOString\(\).split\('T'\)[0];
}

